 41→	standard: { bg: "bg-surface", text: "text-subheading", label: "Standard" },
 42→};
 43→
 44→export function SessionDetailPage() {
 45→	const { sessionId } = useParams<{ sessionId: string }>();
 46→	const { userMap } = useUserMap();
 47→	const [copied, setCopied] = useState(false);
 48→	const [tokenData, setTokenData] = useState<TokenDataPoint[]>([]);
 49→	const [toolActivityData, setToolActivityData] = useState<ToolActivityPoint[]>(
