 59→			setTokenData(data);
 60→			setTotalMessages(total);
 61→		},
 62→		[],
 63→	);
 64→
 65→	const handleToolActivityReady = useCallback((data: ToolActivityPoint[]) => {
 66→		setToolActivityData(data);
 67→	}, []);
 68→
 69→	const handleClickMessage = useCallback((messageIndex: number) => {
 70→		setScrollToIndex(messageIndex);
 71→		// Reset after triggering scroll so it can be re-triggered
 72→		setTimeout(() => setScrollToIndex(null), 100);
 73→	}, []);
 74→
 75→	const { data: session, isLoading } = useQuery(
 76→		orpc.analytics.sessions.detail.queryOptions({
 77→			input: { sessionId: sessionId as string },
 78→		}),
 79→	);
 80→
 81→	const copySessionId = () => {
 82→		if (session) {
 83→			navigator.clipboard.writeText(session.session_id);
 84→			setCopied(true);
 85→			setTimeout(() => setCopied(false), 2000);
 86→		}
 87→	};
 88→
 89→	if (isLoading) {
 90→		return (
 91→			<div className="flex items-center justify-center h-full">
 92→				<div className="animate-pulse space-y-4 w-full max-w-md">
 93→					<div className="h-8 bg-hover rounded w-1/3" />
 94→					<div className="h-4 bg-hover rounded w-1/2" />
 95→					<div className="h-4 bg-hover rounded w-2/3" />
 96→				</div>
 97→			</div>
 98→		);
 99→	}
100→
101→	if (!session) {
102→		return (
103→			<div className="flex items-center justify-center h-full">
104→				<div className="text-center">
105→					<p className="text-status-error-icon text-lg font-semibold mb-2">
106→						Session Not Found
107→					</p>
108→				</div>
109→			</div>
110→		);
111→	}
112→
113→	return (
114→		<div className="flex flex-col h-full">
115→			{/* Session Header — pinned, never scrolls */}
116→			<div className="shrink-0 bg-input px-8 py-4">
117→				<div className="flex items-start justify-between">
118→					<div>
119→						<div className="flex items-center gap-3 mb-2">
120→							<h1 className="text-2xl font-bold text-heading">
121→								Session Details
122→							</h1>
123→							{session.session_archetype &&
124→								(() => {
125→									const style =
126→										archetypeStyles[session.session_archetype] ??
127→										archetypeStyles.standard;
128→									return (
129→										<span
130→											className={`inline-block px-2 py-0.5 text-xs font-medium rounded-full ${style.bg} ${style.text}`}
131→										>
132→											{style.label}
133→										</span>
134→									);
135→								})()}
136→						</div>
137→						<div className="flex items-center gap-4 text-sm text-muted">
138→							<div className="flex items-center gap-2">
139→								<span className="font-mono text-xs bg-surface px-2 py-1 rounded">
140→									{session.session_id.slice(0, 8)}...
141→								</span>
142→								<button
143→									type="button"
144→									onClick={copySessionId}
145→									className="p-1 hover:bg-hover rounded"
146→									title="Copy session ID"
147→								>
148→									{copied ? (
149→										<CheckCircle2 className="w-4 h-4 text-status-success-icon" />
150→									) : (
151→										<Copy className="w-4 h-4 text-muted" />
152→									)}
153→								</button>
154→							</div>
155→							<div className="flex items-center gap-1">
156→								<Clock className="w-4 h-4" />
157→								{formatRelativeTime(session.session_date)}
158→							</div>
159→							<div className="flex items-center gap-1">
160→								<User className="w-4 h-4" />
161→								{formatUsername(session.user_id, userMap)}
162→							</div>
163→						</div>
164→					</div>
165→
166→					{/* KPIs — right side of header */}
167→					<div className="flex items-center gap-6 text-xs">
168→						<div className="text-right">
169→							<p className="text-muted">Duration</p>
170→							<p className="text-foreground font-medium">
171→								{session.duration_min !== undefined
172→									? `${session.duration_min} min`
173→									: "—"}
174→							</p>
175→						</div>
176→						<div className="text-right">
177→							<p className="text-muted">Interactions</p>
178→							<p className="text-foreground font-medium">
179→								{session.total_interactions ?? "—"}
180→							</p>
181→						</div>
182→						<div className="text-right">
183→							<p className="text-muted">Tokens</p>
184→							<p className="text-foreground font-medium">
185→								{session.input_tokens.toLocaleString()} /{" "}
186→								{session.output_tokens.toLocaleString()}
187→							</p>
188→						</div>
189→						<div className="text-right">
190→							<p className="text-muted">Cost</p>
191→							<p className="text-foreground font-mono font-medium">
192→								$
193→								{calculateCost(
194→									session.input_tokens,
195→									session.output_tokens,
196→								).toFixed(4)}
197→							</p>
198→						</div>
199→						{session.success_score !== undefined && (
200→							<div className="text-right">
201→								<p className="text-muted flex items-center">
202→									Score
203→									<InfoTooltip text="Session quality score (0–100): earns points for a git commit (+20), high output ratio (+15), and skills used (+5 each, max 3); loses points for errors (−2 each) and abandoned sessions." />
204→								</p>
205→								<p
206→									className={`font-semibold ${
207→										session.success_score >= 70
208→											? "text-status-success-icon"
209→											: session.success_score >= 40
210→												? "text-status-warning-icon"
211→												: "text-status-error-icon"
212→									}`}
213→								>
214→									{session.success_score.toFixed(0)}/100
215→								</p>
216→							</div>
217→						)}
218→						{Object.keys(session.subagents).length > 0 && (
219→							<div className="text-right">
220→								<p className="text-muted">Subagents</p>
221→								<p className="text-foreground font-medium">
222→									{Object.keys(session.subagents).length}
223→								</p>
224→							</div>
225→						)}
226→					</div>
227→				</div>
228→
229→				<div className="mt-3 flex flex-wrap items-center gap-4 text-sm">
230→					{session.repository && (
231→						<div className="flex items-center gap-2 px-3 py-1 bg-status-info-bg rounded-lg">
232→							<GitBranch className="w-4 h-4 text-accent" />
233→							<span className="text-status-info-text font-medium">
234→								{session.repository}
235→							</span>
236→						</div>
237→					)}
238→					{session.git_branch && (
239→						<div className="flex items-center gap-2 px-3 py-1 bg-status-info-bg rounded-lg">
240→							<GitBranch className="w-4 h-4 text-accent" />
241→							<span className="text-status-info-text font-medium">
242→								{session.git_branch}
243→							</span>
244→						</div>
245→					)}
246→					{session.git_sha && (
247→						<div className="group relative">
248→							<div className="flex items-center gap-2 px-3 py-1 bg-status-info-bg rounded-lg cursor-default">
249→								<GitCommitHorizontal className="w-4 h-4 text-accent" />
250→								<span className="text-status-info-text font-medium">
251→									{session.git_sha.slice(0, 8)}
252→								</span>
253→								<ChevronDown className="w-3 h-3 text-accent transition-transform group-hover:rotate-180" />
254→							</div>
255→							<div className="absolute top-full left-0 mt-1 bg-input border border-border rounded-lg shadow-lg z-20 p-2 min-w-[280px] hidden group-hover:block">
256→								<div className="flex items-center justify-between gap-2 px-2 py-1">
257→									<span className="text-xs font-mono text-foreground select-all">
258→										{session.git_sha}
259→									</span>
260→									<button
261→										type="button"
262→										onClick={() =>
263→											navigator.clipboard.writeText(session.git_sha as string)
264→										}
265→										className="p-1 hover:bg-hover rounded"
266→										title="Copy commit SHA"
267→									>
