 4→
 5→interface FullOrg {
 6→	id: string;
 7→	name: string;
 8→	slug: string;
 9→	members: readonly {
10→		id: string;
11→		userId: string;
12→		role: string;
13→		user: { id: string; name: string; email: string; image: string | null };
14→	}[];
