23→export function useFullOrganization(orgId: string | undefined) {
24→	const queryClient = useQueryClient();
25→	const queryKey = ["full-organization", orgId] as const;
26→
27→	const { data, isLoading } = useQuery({
28→		queryKey,
29→		queryFn: async () => {
30→			const res = await authClient.organization.getFullOrganization({
31→				query: { organizationId: orgId as string },
32→			});
33→			return (res.data as unknown as FullOrg) ?? null;
34→		},
35→		enabled: !!orgId,
