										<Badge
											// biome-ignore lint/suspicious/noArrayIndexKey: tags may duplicate
											key={`${tag}-${idx}`}
											variant="outline"
											className={cn(
												"border-indigo-300 text-indigo-700",
												"dark:border-indigo-700 dark:text-indigo-400",
